
import { ArrowUp } from "lucide-react";
import type {
  CellProps,
  ColumnProps,
  RowProps,
  TableBodyProps,
  TableHeaderProps,
  TableProps as AriaTableProps,
} from "react-aria-components";
import {
  Button,
  Cell as AriaCell,
  Collection,
  Column as AriaColumn,
  ColumnResizer,
  Group,
  ResizableTableContainer,
  Row as AriaRow,
  Table as AriaTable,
  TableBody as AriaTableBody,
  TableHeader as AriaTableHeader,
  composeRenderProps,
  useTableOptions,
} from "react-aria-components";
import { twMerge } from "tailwind-merge";
import { tv } from "tailwind-variants";

import { Checkbox } from "./checkbox";
import { composeTailwindRenderProps, focusRing } from "./utils";

interface Props extends Omit<AriaTableProps, "className"> {
  className?: string;
}

export function Table({ className, onScroll, ...otherProps }: Props) {
  return (
    <ResizableTableContainer
      className={twMerge(
        "tw:relative tw:box-border tw:max-h-80 tw:w-full tw:scroll-pt-[2.281rem] tw:overflow-auto tw:rounded-lg tw:border tw:border-neutral-300 tw:bg-white tw:font-sans",
        className,
      )}
      onScroll={onScroll}
    >
      <AriaTable
        {...otherProps}
        className="tw:box-border tw:border-separate tw:border-spacing-0 tw:overflow-hidden tw:has-[>[data-empty]]:h-full"
      />
    </ResizableTableContainer>
  );
}

const columnStyles = tv({
  extend: focusRing,
  base: "tw:box-border tw:flex tw:h-5 tw:flex-1 tw:items-center tw:gap-1 tw:overflow-hidden tw:px-2",
});

const resizerStyles = tv({
  extend: focusRing,
  base: "tw:box-content tw:h-5 tw:w-px tw:translate-x-2 tw:cursor-col-resize tw:rounded-xs tw:bg-neutral-400 tw:bg-clip-content tw:px-2 tw:py-1 tw:-outline-offset-2 tw:forced-colors:bg-[ButtonBorder] tw:resizing:w-0.5 tw:resizing:bg-blue-600 tw:resizing:pl-1.75 tw:forced-colors:resizing:bg-[Highlight]",
});

export function Column({ className, width, ...otherProps }: ColumnProps) {
  return (
    <AriaColumn
      {...otherProps}
      className={composeTailwindRenderProps(
        className,
        "tw:box-border tw:h-1 tw:cursor-default tw:text-start tw:text-sm tw:font-semibold tw:text-neutral-700 tw:focus-within:z-20 tw:[&:hover]:z-20",
      )}
    >
      {composeRenderProps(
        otherProps.children,
        (children, { allowsSorting, sortDirection }) => (
          <div className="tw:flex tw:items-center">
            <Group role="presentation" tabIndex={-1} className={columnStyles}>
              <span className="tw:truncate">{children}</span>

              {allowsSorting && (
                <span
                  className={`tw:flex tw:h-4 tw:w-4 tw:items-center tw:justify-center tw:transition ${
                    sortDirection === "descending" ? "tw:rotate-180" : ""
                  }`}
                >
                  {sortDirection && (
                    <ArrowUp
                      aria-hidden
                      className="tw:h-4 tw:w-4 tw:text-neutral-500 tw:forced-colors:text-[ButtonText]"
                    />
                  )}
                </span>
              )}
            </Group>

            {!width && <ColumnResizer className={resizerStyles} />}
          </div>
        ),
      )}
    </AriaColumn>
  );
}

export function TableHeader<T extends object>(props: TableHeaderProps<T>) {
  const { selectionBehavior, selectionMode, allowsDragging } =
    useTableOptions();

  return (
    <AriaTableHeader
      {...props}
      className={composeTailwindRenderProps(
        props.className,
        "tw:sticky tw:top-0 tw:z-10 tw:rounded-t-lg tw:border-b tw:border-b-neutral-200 tw:bg-neutral-100/60 tw:backdrop-blur-md tw:supports-[-moz-appearance:none]:bg-neutral-100 tw:forced-colors:bg-[Canvas]",
      )}
    >
      {allowsDragging && <Column />}

      {selectionBehavior === "toggle" && (
        <AriaColumn
          width={36}
          minWidth={36}
          className="tw:box-border tw:cursor-default tw:p-2 tw:text-start tw:text-sm tw:font-semibold"
        >
          {selectionMode === "multiple" && <Checkbox slot="selection" />}
        </AriaColumn>
      )}

      <Collection items={props.columns}>{props.children}</Collection>
    </AriaTableHeader>
  );
}

export function TableBody<T extends object>(props: TableBodyProps<T>) {
  return (
    <AriaTableBody
      {...props}
      className="tw:empty:text-center tw:empty:text-sm tw:empty:italic"
    />
  );
}

const rowStyles = tv({
  extend: focusRing,
  base: "tw:group/row tw:relative tw:cursor-default tw:text-sm tw:text-neutral-900 tw:-outline-offset-2 tw:select-none tw:last:rounded-b-lg tw:hover:bg-neutral-100 tw:disabled:text-neutral-300 tw:pressed:bg-neutral-100 tw:selected:bg-blue-100 tw:selected:hover:bg-blue-200 tw:selected:pressed:bg-blue-200",
});

export function Row<T extends object>({
  id,
  columns,
  children,
  ...otherProps
}: RowProps<T>) {
  const { selectionBehavior, allowsDragging } = useTableOptions();

  return (
    <AriaRow id={id} {...otherProps} className={rowStyles}>
      {allowsDragging && (
        <Cell>
          <Button slot="drag">≡</Button>
        </Cell>
      )}

      {selectionBehavior === "toggle" && (
        <Cell>
          <Checkbox slot="selection" />
        </Cell>
      )}

      <Collection items={columns}>{children}</Collection>
    </AriaRow>
  );
}

const cellStyles = tv({
  extend: focusRing,
  base: "tw:box-border tw:truncate tw:border-b tw:border-b-neutral-200 tw:p-2 tw:-outline-offset-2 tw:[--selected-border:var(--color-blue-200)] tw:[-webkit-tap-highlight-color:transparent] tw:group-last/row:border-b-0 tw:group-selected/row:border-(--selected-border) tw:group-last/row:first:rounded-bl-lg tw:group-last/row:last:rounded-br-lg tw:[:is(:has(+[data-selected])_*)]:border-(--selected-border)",
});

export function Cell(props: CellProps) {
  return <AriaCell {...props} className={cellStyles} />;
}
